/**
 * @summary List ledger accounts
 */
export const getListLedgersUrl = (params?: ListLedgersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/ledger?${stringifiedParams}`
    : `/api/ledger`;
};

export const listLedgers = async (
  params?: ListLedgersParams,
  options?: RequestInit,
): Promise<LedgerListResponse> => {
  return customFetch<LedgerListResponse>(getListLedgersUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListLedgersQueryKey = (params?: ListLedgersParams) => {
  return [`/api/ledger`, ...(params ? [params] : [])] as const;
};

export const getListLedgersQueryOptions = <
  TData = Awaited<ReturnType<typeof listLedgers>>,
  TError = ErrorType<unknown>,
>(
  params?: ListLedgersParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listLedgers>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListLedgersQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listLedgers>>> = ({
    signal,
  }) => listLedgers(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listLedgers>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

